SELECT COUNT(*) AS failed_test_cases
FROM test_cases
WHERE result = 'FAILURE' AND title LIKE '%integration%';

SELECT * 
FROM test_cases 
WHERE result = 'FAILURE' AND priority = 1;

SELECT tc.title, tc.test_case_type
FROM test_cases tc
INNER JOIN defects d ON tc.test_case_id = d.test_case_id;

SELECT AVG(tr.duration) AS average_duration
FROM test_results tr
WHERE tr.test_case_id IN (
    SELECT tc.test_case_id FROM test_cases tc WHERE tc.test_case_type = 'Staging'
);

SELECT test_case_id, title, duration
FROM test_cases
WHERE duration > (
  SELECT AVG(duration)
  FROM test_cases
);

SELECT COUNT(*) AS high_priority_test_case_count
FROM test_cases
WHERE priority = 1;

SELECT tc.*, us.title AS user_story_title, us.description AS user_story_description
FROM test_cases tc
JOIN user_stories us ON tc.story_id = us.story_id;

SELECT * 
FROM test_execution_logs
WHERE status = 'SUCCESS';

SELECT AVG(tc.duration) AS AverageDuration
FROM test_cases tc
INNER JOIN test_results tr ON tc.test_case_id = tr.test_case_id;

SELECT tag_name, COUNT(test_case_id) AS test_cases
FROM test_case_tags
GROUP BY tag_name;
